#!/bin/bash
# wk-im-detect-env.sh
# Detects repo type and outputs JSON with each known component's resolved path.
# Component names come from components.conf (not hardcoded), so the same logic
# serves any 1..N component agent generated by create-wk-agent.
#
# Output: {"env":"component|main-app|unknown-pod|unknown","components":{"<Name>":"<path>",...}}

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
# shellcheck source=wk-im-components.sh
. "$SCRIPT_DIR/wk-im-components.sh"

CWD="${1:-$(pwd)}"
CWD="$(cd "$CWD" && pwd)"

json_escape() {
  printf '%s' "$1" | sed 's/\\/\\\\/g; s/"/\\"/g'
}

# emit_json <env> <name1> <path1> [<name2> <path2> ...]
emit_json() {
  local env="$1"; shift
  printf '{"env":"%s","components":{' "$(json_escape "$env")"
  local first=1
  while [ "$#" -ge 2 ]; do
    [ "$first" -eq 1 ] || printf ','
    printf '"%s":"%s"' "$(json_escape "$1")" "$(json_escape "$2")"
    first=0
    shift 2
  done
  printf '}}\n'
}

detect_component_name() {
  local dir="$1" spec
  spec="$(find "$dir" -maxdepth 1 -name "*.podspec" 2>/dev/null | head -1 || true)"
  [ -n "$spec" ] && basename "$spec" .podspec
}

resolve_path() {
  local base="$1" rel="$2" candidate
  [ -n "$rel" ] || return 0
  case "$rel" in
    /*) candidate="$rel" ;;
    *)  candidate="$base/$rel" ;;
  esac
  cd "$candidate" 2>/dev/null && pwd
}

pod_path_for() {
  local podfile="$1" pod_name="$2" line path
  line="$(grep -E "^[[:space:]]*pod[[:space:]]+['\"]$pod_name['\"]" "$podfile" 2>/dev/null | head -1 || true)"
  [ -n "$line" ] || return 0
  path="$(printf '%s\n' "$line" | sed -nE "s/.*:?path[[:space:]]*=>[[:space:]]*['\"]([^'\"]+)['\"].*/\1/p" | head -1)"
  if [ -z "$path" ]; then
    path="$(printf '%s\n' "$line" | sed -nE "s/.*path:[[:space:]]*['\"]([^'\"]+)['\"].*/\1/p" | head -1)"
  fi
  printf '%s\n' "$path"
}

# Known component names from the manifest.
NAMES="$(wk_component_names)"

# Case 1: cwd is a component pod (podspec basename matches a known component).
COMP="$(detect_component_name "$CWD" || true)"
if [ -n "$COMP" ]; then
  if printf '%s\n' "$NAMES" | grep -qx "$COMP"; then
    emit_json "component" "$COMP" "$CWD"
    exit 0
  fi
  emit_json "unknown-pod"
  exit 0
fi

# Case 2: cwd is a HostApp whose Podfile references every known component.
if [ -f "$CWD/Podfile" ] && [ -n "$NAMES" ]; then
  all_present=1
  while IFS= read -r name; do
    [ -n "$name" ] || continue
    grep -q "$name" "$CWD/Podfile" 2>/dev/null || { all_present=0; break; }
  done <<EOF
$NAMES
EOF
  if [ "$all_present" -eq 1 ]; then
    ARGS=()
    while IFS= read -r name; do
      [ -n "$name" ] || continue
      rel="$(pod_path_for "$CWD/Podfile" "$name")"
      abs="$(resolve_path "$CWD" "$rel" || true)"
      ARGS+=("$name" "$abs")
    done <<EOF
$NAMES
EOF
    emit_json "main-app" "${ARGS[@]}"
    exit 0
  fi
fi

emit_json "unknown"
